SELECT COUNT(DISTINCT u.id) AS total_users_with_roles
FROM users u
INNER JOIN user_roles ur ON u.id = ur.user_id;

SELECT COUNT(DISTINCT a.id) AS total_addresses_with_demographics
FROM addresses a
INNER JOIN address_demographics ad ON a.id = ad.address_id;

SELECT COUNT(id) AS total_matched_addresses
FROM addresses
WHERE matchedness = 'Match' AND state_code = 1;

SELECT SUM(population) AS total_population
FROM demographics
WHERE county_code = 123;

SELECT SUM(d.population) AS total_population
FROM demographics d
WHERE d.state_code = 'CA' AND d.county_code = 'Los Angeles';

SELECT AVG(median_income) AS average_median_income
FROM demographics
WHERE state_code = 123 AND county_code = 45;

SELECT state_code, matchedness, exactness, COUNT(address) AS total_addresses
FROM addresses
GROUP BY state_code, matchedness, exactness;

SELECT COUNT(*) 
FROM addresses 
WHERE matchedness = 'Match';

SELECT d.tract_code, AVG(d.population) AS average_population
FROM demographics d
GROUP BY d.tract_code;
